/**
 * ai-controller.js — AI Scan page controller (camera first).
 *
 * The main experience is a camera scan that feels like the curated AR mode, but
 * the exhibit is generated by AI instead of a MindAR target:
 *
 *   1. Warm intro screen → ask for the camera (getUserMedia, rear camera).
 *   2. Live feed + a transparent scan overlay ("Point your camera at food waste").
 *   3. After the camera is ready we capture ONE frame and POST it to
 *      /api/analyze-food. We never stream frames, so there is no API spam.
 *   4. If the snapshot clearly shows food waste we render an AI exhibit that
 *      mirrors the normal mode (title, fact, actions, Ask more, Quick check).
 *   5. If the frame is unclear we show a friendly retry, with up to one extra
 *      automatic attempt before handing control back to the user.
 *
 * A "Choose image instead" fallback reuses the same analysis path for desktop
 * or when the camera is unavailable. Everything is optional: if the API has no
 * keys or fails, the page points the user back to the curated AR Scan / Demo.
 *
 * Privacy: the captured frame lives only in memory for the preview and result.
 * Nothing is written to localStorage and the camera is stopped when we leave.
 */

import { t, getLocale, initI18n, mountLanguageSwitcher } from './i18n.js';
import { actionLabel } from './food-targets.js';
import { saveLastAction, getAiGuideSeen, setAiGuideSeen } from './storage.js';
import { normalizeResult } from './ai-schema.js';
import { renderAiResult } from './ai-result-renderer.js';
import { debug, isSecureContext, prefersReducedMotion } from './utils.js';

const MAX_FILE_BYTES = 12 * 1024 * 1024; // reject huge originals before compressing
const MAX_DIM = 1280;                    // longest edge of the captured/compressed frame
const JPEG_QUALITY = 0.82;
const MAX_AUTO_SCANS = 2;                 // one automatic scan + at most one auto retry
const AUTO_RETRY_DELAY = 900;            // ms between automatic attempts
const VIDEO_READY_TIMEOUT = 4000;        // ms to wait for the first video frame

// --- runtime state ---
let mediaStream = null;
let currentResult = null;
let currentDataUrl = null;   // the captured/chosen frame (in memory only)
let scanning = false;        // an analyse call is in flight
let autoScansDone = 0;       // automatic attempts used this cycle
let scanCycleStarted = false;
let resultShown = false;
let currentStatusKey = null;

// --- refs: camera layer ---
const video = document.getElementById('ai-video');
const canvas = document.getElementById('ai-canvas');
const freeze = document.getElementById('ai-freeze');

// --- refs: status screen ---
const statusScreen = document.getElementById('ai-status-screen');
const statusIcon = document.getElementById('ai-status-icon');
const statusTitle = document.getElementById('ai-status-title');
const statusMessage = document.getElementById('ai-status-message');
const statusSpinner = document.getElementById('ai-status-spinner');
const statusPrivacy = document.getElementById('ai-status-privacy');
const statusTroubleshoot = document.getElementById('ai-status-troubleshoot');
const useCameraBtn = document.getElementById('ai-use-camera');
const tryAgainBtn = document.getElementById('ai-try-again');
const chooseImageBtn = document.getElementById('ai-choose-image');

// --- refs: chrome + overlays ---
const topbar = document.getElementById('ai-topbar');
const langMount = document.getElementById('ai-lang-mount');
const resultLangMount = document.getElementById('ai-result-lang-mount');
const scanOverlay = document.getElementById('ai-scan-overlay');
const analysingOverlay = document.getElementById('ai-analysing');
const retryOverlay = document.getElementById('ai-retry-overlay');
const retryMsg = document.getElementById('ai-retry-msg');
const retryScanBtn = document.getElementById('ai-retry-scan');
const retryChooseBtn = document.getElementById('ai-retry-choose');

// --- refs: result screen ---
const resultMain = document.getElementById('ai-result-main');
const resultImg = document.getElementById('ai-result-img');
const feedbackEl = document.getElementById('ai-feedback');
const scanAgainBtn = document.getElementById('ai-scan-again');

// --- refs: guide ---
const guideEl = document.getElementById('ai-guide');
const guideBackdrop = document.getElementById('ai-guide-backdrop');
const guideDismiss = document.getElementById('ai-guide-dismiss');
const howToBtn = document.getElementById('ai-howto-btn');

// --- refs: file fallback ---
const fileInput = document.getElementById('ai-file');

// --- refs: ask-more drawer ---
const drawer = document.getElementById('askmore');
const drawerBackdrop = document.getElementById('askmore-backdrop');
const drawerClose = document.getElementById('askmore-close');
const askMoreBtn = document.getElementById('ai-askmore');
const dLook = document.getElementById('askmore-look');
const dWhy = document.getElementById('askmore-why');
const dDo = document.getElementById('askmore-do');
const dSafety = document.getElementById('askmore-safety');
const dFollowWrap = document.getElementById('askmore-followups-wrap');
const dFollow = document.getElementById('askmore-followups');
const askInput = document.getElementById('askmore-q');
const askBtn = document.getElementById('askmore-ask');
const askAnswer = document.getElementById('askmore-answer');

debug('ai-controller.js (camera scan) loaded');

// Translate the static chrome, set <html lang>, then mount the switcher in both
// the camera top bar and the result screen so language stays switchable.
initI18n();
if (langMount) mountLanguageSwitcher(langMount);
if (resultLangMount) mountLanguageSwitcher(resultLangMount);
if (prefersReducedMotion()) document.body.classList.add('reduced-motion');

// ===========================================================================
// Status screen — intro + every camera / API state
// Flags decide the icon, spinner, and which buttons show.
// ===========================================================================
const STATUS_META = {
  intro:        { icon: '📷', spinner: false, titleKey: 'ai.cta',                       msgKey: 'ai.intro',                       useCamera: true,  tryAgain: false, chooseImage: true,  troubleshoot: false, privacy: true },
  permission:   { icon: '📷', spinner: true,  titleKey: 'scan.status.permission.title', msgKey: 'scan.status.permission.message', useCamera: false, tryAgain: false, chooseImage: false, troubleshoot: false, privacy: false },
  starting:     { icon: '📷', spinner: true,  titleKey: 'scan.status.starting.title',   msgKey: 'scan.status.starting.message',   useCamera: false, tryAgain: false, chooseImage: false, troubleshoot: false, privacy: false },
  insecure:     { icon: '🔒', spinner: false, titleKey: 'scan.status.insecure.title',   msgKey: 'scan.status.insecure.message',   useCamera: false, tryAgain: true,  chooseImage: true,  troubleshoot: true,  privacy: false },
  unsupported:  { icon: '🚫', spinner: false, titleKey: 'scan.status.unsupported.title',msgKey: 'scan.status.unsupported.message',useCamera: false, tryAgain: false, chooseImage: true,  troubleshoot: true,  privacy: false },
  denied:       { icon: '⛔', spinner: false, titleKey: 'scan.status.denied.title',     msgKey: 'scan.status.denied.message',     useCamera: false, tryAgain: true,  chooseImage: true,  troubleshoot: true,  privacy: false },
  nocamera:     { icon: '🎥', spinner: false, titleKey: 'scan.status.nocamera.title',   msgKey: 'scan.status.nocamera.message',   useCamera: false, tryAgain: false, chooseImage: true,  troubleshoot: true,  privacy: false },
  inuse:        { icon: '🎥', spinner: false, titleKey: 'scan.status.inuse.title',      msgKey: 'scan.status.inuse.message',      useCamera: false, tryAgain: true,  chooseImage: true,  troubleshoot: true,  privacy: false },
  camfailed:    { icon: '⚠️', spinner: false, titleKey: 'ai.camFailedTitle',            msgKey: 'ai.camFailedMsg',                useCamera: false, tryAgain: true,  chooseImage: true,  troubleshoot: true,  privacy: false },
  unavailable:  { icon: '☁️', spinner: false, titleKey: 'ai.unavailableTitle',          msgKey: 'ai.errUnavailable',              useCamera: false, tryAgain: true,  chooseImage: true,  troubleshoot: false, privacy: false },
  notconfigured:{ icon: '⚙️', spinner: false, titleKey: 'ai.notConfiguredTitle',        msgKey: 'ai.errNotConfigured',            useCamera: false, tryAgain: false, chooseImage: true,  troubleshoot: false, privacy: false },
};

function setStatus(key) {
  const meta = STATUS_META[key];
  if (!meta || !statusScreen) return;
  currentStatusKey = key;
  hideCameraLayer();
  hideAllOverlays();
  if (resultMain) resultMain.hidden = true;
  statusScreen.hidden = false;
  statusIcon.textContent = meta.icon;
  statusTitle.textContent = t(meta.titleKey) || '';
  statusMessage.textContent = t(meta.msgKey) || '';
  statusSpinner.hidden = !meta.spinner;
  statusTroubleshoot.hidden = !meta.troubleshoot;
  statusPrivacy.hidden = !meta.privacy;
  useCameraBtn.hidden = !meta.useCamera;
  tryAgainBtn.hidden = !meta.tryAgain;
  chooseImageBtn.hidden = !meta.chooseImage;
  debug('AI status →', key);
}

/** Show the intro screen with an inline error message (bad file type / size). */
function showImageError(errKey) {
  setStatus('intro');
  statusMessage.textContent = t(`ai.${errKey}`) || '';
}

// ===========================================================================
// Layer helpers — camera feed, frozen snapshot, scan / analysing / retry
// ===========================================================================
function hideCameraLayer() {
  if (video) video.hidden = true;
  if (freeze) freeze.hidden = true;
  if (topbar) topbar.hidden = true;
}
function hideAllOverlays() {
  if (scanOverlay) scanOverlay.hidden = true;
  if (analysingOverlay) analysingOverlay.hidden = true;
  if (retryOverlay) retryOverlay.hidden = true;
}

/** Live feed + "point your camera" scanner animation. */
function enterScanning() {
  statusScreen.hidden = true;
  resultMain.hidden = true;
  freeze.hidden = true;
  video.hidden = false;
  topbar.hidden = false;
  hideAllOverlays();
  scanOverlay.hidden = false;
}
/** Frozen snapshot + "analysing snapshot" spinner while the API runs. */
function enterAnalysing() {
  statusScreen.hidden = true;
  resultMain.hidden = true;
  freeze.hidden = false;
  topbar.hidden = false;
  hideAllOverlays();
  analysingOverlay.hidden = false;
}
/** Friendly retry card over the live feed. */
function enterRetry(message) {
  statusScreen.hidden = true;
  resultMain.hidden = true;
  freeze.hidden = true;
  video.hidden = false;
  topbar.hidden = false;
  hideAllOverlays();
  retryOverlay.hidden = false;
  if (message && retryMsg) retryMsg.textContent = message;
}

// ===========================================================================
// Camera lifecycle
// ===========================================================================
function classifyCameraError(err) {
  const name = (err && err.name) || '';
  debug('Camera error:', name, err && err.message);
  switch (name) {
    case 'NotAllowedError': case 'PermissionDeniedError': case 'SecurityError': return 'denied';
    case 'NotFoundError': case 'DevicesNotFoundError': case 'OverconstrainedError': case 'ConstraintNotSatisfiedError': return 'nocamera';
    case 'NotReadableError': case 'TrackStartError': case 'AbortError': return 'inuse';
    default: return 'camfailed';
  }
}

/** Resolve once the video has real dimensions (or after a short timeout). */
function waitForVideoReady() {
  return new Promise((resolve) => {
    if (video.videoWidth && video.videoHeight) return resolve();
    const done = () => { cleanup(); resolve(); };
    const to = setTimeout(done, VIDEO_READY_TIMEOUT);
    function cleanup() {
      clearTimeout(to);
      video.removeEventListener('loadedmetadata', done);
      video.removeEventListener('playing', done);
    }
    video.addEventListener('loadedmetadata', done, { once: true });
    video.addEventListener('playing', done, { once: true });
  });
}

async function startCameraFlow() {
  setStatus('permission');
  if (!isSecureContext()) { setStatus('insecure'); return; }
  if (!navigator.mediaDevices || !navigator.mediaDevices.getUserMedia) { setStatus('unsupported'); return; }

  let stream;
  try {
    // Prefer the rear camera on phones; fall back to any camera.
    stream = await navigator.mediaDevices.getUserMedia({ video: { facingMode: { ideal: 'environment' } }, audio: false });
  } catch (err) {
    setStatus(classifyCameraError(err));
    return;
  }

  mediaStream = stream;
  video.srcObject = stream;
  try { await video.play(); } catch { /* autoplay quirks are non-fatal */ }
  await waitForVideoReady();

  if (!video.videoWidth || !video.videoHeight) { stopCamera(); setStatus('camfailed'); return; }
  onCameraReady();
}

function onCameraReady() {
  statusScreen.hidden = true;
  scanCycleStarted = false;
  enterScanning();
  debug('AI camera ready');
  // First-time users see the guide first; the first scan starts when it closes.
  if (!getAiGuideSeen()) {
    setTimeout(openGuide, 400);
  } else {
    beginScanCycle();
  }
}

function restartCameraFlow() {
  stopCamera();
  resultShown = false;
  scanCycleStarted = false;
  currentResult = null;
  startCameraFlow();
}

function stopCamera() {
  if (mediaStream) {
    mediaStream.getTracks().forEach((tr) => { try { tr.stop(); } catch { /* noop */ } });
    mediaStream = null;
  }
  try { video.srcObject = null; } catch { /* noop */ }
}

// ===========================================================================
// Frame capture + scan cycle
// ===========================================================================
function captureFrame() {
  const vw = video.videoWidth;
  const vh = video.videoHeight;
  if (!vw || !vh) return null;
  const scale = Math.min(1, MAX_DIM / Math.max(vw, vh));
  const w = Math.max(1, Math.round(vw * scale));
  const h = Math.max(1, Math.round(vh * scale));
  canvas.width = w;
  canvas.height = h;
  const ctx = canvas.getContext('2d');
  if (!ctx) return null;
  ctx.drawImage(video, 0, 0, w, h);
  try { return canvas.toDataURL('image/jpeg', JPEG_QUALITY); } catch { return null; }
}

/** Begin a fresh scan cycle from the live feed (first attempt is automatic). */
function beginScanCycle() {
  if (resultShown || scanning) return;
  scanCycleStarted = true;
  autoScansDone = 1;
  runScan(true);
}

async function runScan(isAuto) {
  if (scanning) return;
  if (!mediaStream) { startCameraFlow(); return; } // camera was stopped — restart

  const dataUrl = captureFrame();
  if (!dataUrl) {
    if (isAuto && autoScansDone < MAX_AUTO_SCANS) {
      autoScansDone++;
      enterScanning();
      setTimeout(() => { if (!resultShown && !scanning) runScan(true); }, AUTO_RETRY_DELAY);
    } else {
      enterRetry(t('ai.retryHint'));
    }
    return;
  }

  scanning = true;
  currentDataUrl = dataUrl;
  freeze.src = dataUrl;
  enterAnalysing();

  const res = await postAnalyze(dataUrl, 'camera');
  scanning = false;
  if (resultShown) return;
  handleCameraOutcome(res, isAuto);
}

function handleCameraOutcome(res, isAuto) {
  if (!res.ok) {
    stopCamera(); // not going to auto-rescan — release the camera
    setStatus(res.code === 'not_configured' ? 'notconfigured' : 'unavailable');
    return;
  }
  let result;
  try {
    result = normalizeResult(res.result, getLocale());
    result.provider = res.result.provider;
  } catch {
    stopCamera();
    setStatus('unavailable');
    return;
  }

  if (shouldShowResult(result)) { showResult(result); return; }

  // Frame was unclear — try once more automatically, then ask the user.
  if (isAuto && autoScansDone < MAX_AUTO_SCANS) {
    autoScansDone++;
    enterScanning();
    setTimeout(() => { if (!resultShown && !scanning) runScan(true); }, AUTO_RETRY_DELAY);
    return;
  }
  enterRetry(result.detectionMessage || t('ai.retryHint'));
}

/**
 * Decide whether a result is solid enough to show, or whether we should ask the
 * user to scan again. Mirrors the rules in the AI Scan spec.
 */
function shouldShowResult(r) {
  if (r.sceneStatus === 'not_food_waste') {
    return r.visibleItems.length > 0 && r.confidence === 'high';
  }
  if (r.sceneStatus === 'unclear') {
    return r.visibleItems.length > 0 && (r.confidence === 'high' || r.confidence === 'medium');
  }
  // "detected" (and the default when the model omits the field)
  if (r.visibleItems.length > 0) return true;
  return r.confidence === 'medium' || r.confidence === 'high';
}

async function postAnalyze(dataUrl, source) {
  let resp;
  try {
    resp = await fetch('/api/analyze-food', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ image: dataUrl, locale: getLocale(), source }),
    });
  } catch {
    return { ok: false, code: 'unavailable' };
  }
  let data = null;
  try { data = await resp.json(); } catch { data = null; }
  if (resp.status === 503 || data?.error === 'not_configured') return { ok: false, code: 'not_configured' };
  if (!resp.ok || !data?.ok || !data.result) return { ok: false, code: 'unavailable' };
  return { ok: true, result: data.result };
}

// ===========================================================================
// Result screen
// ===========================================================================
function showResult(result) {
  currentResult = result;
  resultShown = true;
  stopCamera(); // the snapshot is already captured; free the camera

  hideAllOverlays();
  statusScreen.hidden = true;
  video.hidden = true;
  freeze.hidden = true;
  topbar.hidden = true;

  resultImg.src = currentDataUrl;
  resultImg.alt = result.arTitle || '';
  renderAiResult(result);
  resultMain.hidden = false;
  resultMain.scrollTop = 0;

  // Optional haptic confirmation (never relied upon).
  if (navigator.vibrate) { try { navigator.vibrate(40); } catch { /* noop */ } }
  debug('AI result shown — provider:', result.provider, 'scene:', result.sceneStatus, 'action:', result.recommendedAction);
}

// ===========================================================================
// Actions (target-specific guidance from the AI result)
// ===========================================================================
function applyAction(action) {
  if (!currentResult) return;
  const guidance = currentResult.guidance[action] || '';
  feedbackEl.textContent = `${actionLabel(action)}: ${guidance}`;
  feedbackEl.className = 'feedback-panel';
  if (action === 'throwAway') feedbackEl.classList.add('feedback-panel--negative');
  else if (action === currentResult.recommendedAction) feedbackEl.classList.add('feedback-panel--positive');
  else feedbackEl.classList.add('feedback-panel--neutral');
  saveLastAction(action); // so Quick Check can recall it
  debug('AI action:', action);
}

// ===========================================================================
// Ask-more drawer (static content + optional contextual question)
// ===========================================================================
function fillDrawer() {
  if (!currentResult) return;
  const visible = currentResult.visibleItems.length ? currentResult.visibleItems.join(', ') : '—';
  const uncertain = currentResult.uncertainItems.length ? ` (${currentResult.uncertainItems.join(', ')})` : '';
  dLook.textContent = `${visible}${uncertain}`;
  dWhy.textContent = currentResult.actionReason;
  dDo.textContent = `${actionLabel(currentResult.recommendedAction)}: ${currentResult.guidance[currentResult.recommendedAction] || ''}`;
  dSafety.textContent = currentResult.safetyNote;

  if (currentResult.followUpQuestions.length) {
    dFollow.innerHTML = currentResult.followUpQuestions
      .map((q) => `<li><button type="button" class="askmore-suggest">${escapeHtml(q)}</button></li>`)
      .join('');
    dFollowWrap.hidden = false;
    dFollow.querySelectorAll('.askmore-suggest').forEach((b) => {
      b.addEventListener('click', () => { if (askInput) askInput.value = b.textContent; });
    });
  } else {
    dFollowWrap.hidden = true;
  }
  if (askAnswer) askAnswer.hidden = true;
}
function escapeHtml(s) {
  return String(s).replace(/[&<>"']/g, (c) => ({ '&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;', "'": '&#39;' }[c]));
}
function openDrawer() {
  if (!drawer || !currentResult) return;
  fillDrawer();
  drawer.removeAttribute('hidden');
  requestAnimationFrame(() => drawer.classList.add('is-open'));
  drawerClose?.focus();
}
function closeDrawer() {
  if (!drawer) return;
  drawer.classList.remove('is-open');
  drawer.setAttribute('hidden', '');
}

async function askQuestion() {
  if (!currentResult || !askInput) return;
  const question = askInput.value.trim();
  if (!question) return;
  askBtn.disabled = true;
  askAnswer.hidden = false;
  askAnswer.textContent = t('ai.analysing') || 'Analysing…';

  let resp;
  try {
    resp = await fetch('/api/ask-food', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ question, analysisResult: currentResult, locale: getLocale() }),
    });
  } catch {
    askAnswer.textContent = t('ai.errUnavailable') || '';
    askBtn.disabled = false;
    return;
  }
  let data = null;
  try { data = await resp.json(); } catch { data = null; }
  askAnswer.textContent = data?.ok && data.answer ? data.answer : t('ai.errUnavailable') || '';
  askBtn.disabled = false;
}

// ===========================================================================
// Upload fallback (secondary path — same analysis)
// ===========================================================================
function readFileAsDataURL(file) {
  return new Promise((resolve, reject) => {
    const fr = new FileReader();
    fr.onload = () => resolve(fr.result);
    fr.onerror = () => reject(new Error('read failed'));
    fr.readAsDataURL(file);
  });
}
function loadImage(src) {
  return new Promise((resolve, reject) => {
    const img = new Image();
    img.onload = () => resolve(img);
    img.onerror = () => reject(new Error('decode failed'));
    img.src = src;
  });
}
async function compressImage(file) {
  const dataUrl = await readFileAsDataURL(file);
  let img;
  try {
    img = await loadImage(dataUrl);
  } catch {
    return dataUrl; // some formats (e.g. HEIC) can't be decoded by canvas — send raw
  }
  const scale = Math.min(1, MAX_DIM / Math.max(img.width, img.height));
  const w = Math.max(1, Math.round(img.width * scale));
  const h = Math.max(1, Math.round(img.height * scale));
  const c = document.createElement('canvas');
  c.width = w;
  c.height = h;
  c.getContext('2d').drawImage(img, 0, 0, w, h);
  try { return c.toDataURL('image/jpeg', JPEG_QUALITY); } catch { return dataUrl; }
}

async function handleFile(file) {
  if (!file) return;
  if (!file.type || !file.type.startsWith('image/')) { showImageError('errType'); return; }
  if (file.size > MAX_FILE_BYTES) { showImageError('errTooLarge'); return; }

  let dataUrl;
  try { dataUrl = await compressImage(file); } catch { showImageError('errType'); return; }

  // The chosen image replaces any camera capture; stop the live feed.
  stopCamera();
  resultShown = false;
  currentDataUrl = dataUrl;
  freeze.src = dataUrl;
  enterAnalysing();

  const res = await postAnalyze(dataUrl, 'upload');
  if (!res.ok) {
    setStatus(res.code === 'not_configured' ? 'notconfigured' : 'unavailable');
    return;
  }
  let result;
  try {
    result = normalizeResult(res.result, getLocale());
    result.provider = res.result.provider;
  } catch {
    setStatus('unavailable');
    return;
  }
  // A user-chosen image is always shown (they picked it on purpose). The
  // detected badge hides itself if the AI did not see a clear food-waste scene.
  showResult(result);
}

// ===========================================================================
// First-time "How AI Scan works" guide
// ===========================================================================
function openGuide() {
  if (!guideEl) return;
  guideEl.hidden = false;
  guideDismiss?.focus();
}
function closeGuide() {
  if (guideEl) guideEl.hidden = true;
  setAiGuideSeen();
  // Start the first scan once the guide is dismissed (camera must be running).
  if (!scanCycleStarted && mediaStream) beginScanCycle();
}

// ===========================================================================
// Wire up
// ===========================================================================
useCameraBtn?.addEventListener('click', startCameraFlow);
tryAgainBtn?.addEventListener('click', restartCameraFlow);
chooseImageBtn?.addEventListener('click', () => fileInput?.click());
retryChooseBtn?.addEventListener('click', () => fileInput?.click());
fileInput?.addEventListener('change', (e) => handleFile(e.target.files && e.target.files[0]));

retryScanBtn?.addEventListener('click', () => { if (!scanning) beginScanCycle(); });
scanAgainBtn?.addEventListener('click', () => { resultShown = false; currentResult = null; startCameraFlow(); });

document.querySelectorAll('#ai-actions [data-action]').forEach((btn) => {
  btn.addEventListener('click', () => applyAction(btn.dataset.action));
});

askMoreBtn?.addEventListener('click', openDrawer);
drawerBackdrop?.addEventListener('click', closeDrawer);
drawerClose?.addEventListener('click', closeDrawer);
askBtn?.addEventListener('click', askQuestion);

howToBtn?.addEventListener('click', openGuide);
guideDismiss?.addEventListener('click', closeGuide);
guideBackdrop?.addEventListener('click', closeGuide);

document.addEventListener('keydown', (e) => {
  if (e.key !== 'Escape') return;
  if (drawer && !drawer.hasAttribute('hidden')) closeDrawer();
  else if (guideEl && !guideEl.hidden) closeGuide();
});

// Stop the camera when the page is hidden or unloaded (privacy + battery).
window.addEventListener('pagehide', stopCamera);
window.addEventListener('beforeunload', stopCamera);

// Re-localise dynamic content on language change (static DOM is handled by i18n).
window.addEventListener('platewise:localechange', () => {
  if (currentStatusKey && statusScreen && !statusScreen.hidden) setStatus(currentStatusKey);
  if (currentResult && resultMain && !resultMain.hidden) renderAiResult(currentResult);
  if (drawer && !drawer.hasAttribute('hidden')) fillDrawer();
});

// Start on the warm intro screen — the camera opens when the user taps "Use camera".
setStatus('intro');
